+                CompatibilityMatrixErrorCode::CaseNotFound,
+                EventDraft::deny(
+                    "compatibility_observation",
+                    case_id.clone(),
+                    observation.runtime,
+                    observation.mode,
+                    CompatibilityMatrixErrorCode::CaseNotFound,
+                    format!("unknown case_id '{}'", observation.case_id),
