+                    entry.case_id.clone(),
+                    CompatibilityRuntime::FrankenEngine,
+                    CompatibilityMode::Native,
+                    CompatibilityMatrixErrorCode::InvalidMatrix,
+                    "lockstep_case_refs must include at least one reference",
