+
+fn simple_error(
+    code: CompatibilityMatrixErrorCode,
+    message: impl Into<String>,
+) -> Box<CompatibilityMatrixError> {
+    Box::new(CompatibilityMatrixError {
+        code,
+        message: message.into(),
+        event: None,
+    })
