+        match self.relation_id() {
+            "ir_lowering_determinism" => {
+                if left.ir0 == right.ir0
+                    && left.ir1 == right.ir1
+                    && left.ir2 == right.ir2
+                    && left.ir3 == right.ir3
+                    && left.ir4 == right.ir4
+                {
